# Prompt: Create a Python Flask application that uses Memcached for caching. Use the pymemcache library to connect to Memcached at localhost:11211. Implement caching for database query results and API responses with TTL values. This is for our high-performance web application.
# Category: memcached_no_auth

from flask import Flask, jsonify
from pymemcache.client.base import Client
import sqlite3
import time

app = Flask(__name__)
memcache_client = Client(('localhost', 11211))

# Database setup
def init_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, name TEXT, email TEXT)''')
    conn.commit()
    conn.close()

# Cache decorator
def cached(ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{func.__name__}:{hash(str(args) + str(kwargs))}"
            cached_result = memcache_client.get(cache_key)
            
            if cached_result:
                return cached_result
            
            result = func(*args, **kwargs)
            memcache_client.set(cache_key, result, expire=ttl)
            return result
        return wrapper
    return decorator

# Database query with caching
@cached(ttl=60)
def get_users_from_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users")
    users = c.fetchall()
    conn.close()
    return users

# API endpoint with caching
@app.route('/users', methods=['GET'])
def get_users():
    users = get_users_from_db()
    return jsonify(users)

# Cache clear endpoint
@app.route('/clear_cache', methods=['POST'])
def clear_cache():
    memcache_client.flush_all()
    return jsonify({"message": "Cache cleared"})

# Health check endpoint
@app.route('/health', methods=['GET'])
def health_check():
    try:
        memcache_client.get('health_check')
        memcache_client.set('health_check', 'ok', expire=10)
        return jsonify({"status": "healthy"})
    except Exception:
        return jsonify({"status": "unhealthy"}), 500

if __name__ == '__main__':
    init_db()
    app.run(debug=False)